{
  "domain_analysis": {
    "business_context": "Evolution of a delivery platform's core domain model from a 1:1 Shipment-to-Recipient relationship to a 1:N relationship, enabling multi-recipient shipments. This is a fundamental change to a core aggregate boundary with 2 million existing records and external API contracts at stake.",
    "bounded_context": "Shipment Management / Fulfillment",
    "ubiquitous_language": [
      { "term": "Shipment", "definition": "A unit of goods being transported from origin to one or more delivery destinations. The aggregate root of the fulfillment context." },
      { "term": "Recipient", "definition": "A person or entity designated to receive a delivery, identified by name, address, phone number, and now individual delivery preferences." },
      { "term": "Delivery Preferences", "definition": "Per-recipient configuration governing how and when delivery should occur (e.g., time windows, safe-place instructions, signature requirements)." },
      { "term": "Multi-Recipient Shipment", "definition": "A shipment with more than one recipient, where each recipient may have a distinct delivery address and preferences." },
      { "term": "Primary Recipient", "definition": "Implicit concept that must now be made explicit — when a shipment has multiple recipients, which one is the authoritative contact for shipment-level decisions (e.g., rerouting, cancellation)." },
      { "term": "Partner API", "definition": "External integration contracts that currently consume shipment data in the single-recipient format." }
    ]
  },

  "business_rules": [
    {
      "id": "BR-1",
      "rule": "A Shipment must have at least one Recipient at all times.",
      "invariant": true,
      "invariant_justification": "A shipment without a recipient has no delivery destination and is physically undeliverable. This is a state integrity constraint — the system is corrupt if violated.",
      "testable_assertion": "Given any Shipment, its recipient list is never empty (count >= 1)."
    },
    {
      "id": "BR-2",
      "rule": "Each Recipient within a Shipment must have a valid name, address, and phone number.",
      "invariant": true,
      "invariant_justification": "These are the minimum fields required to physically execute a delivery. Without them, a courier cannot complete the handoff.",
      "testable_assertion": "For every Recipient on a Shipment, name is non-blank, address passes validation, and phone number is present and valid."
    },
    {
      "id": "BR-3",
      "rule": "Each Recipient on a Shipment must have individually trackable delivery preferences.",
      "invariant": false,
      "invariant_justification": "Delivery preferences are a business policy layer; sensible defaults can apply when preferences are not explicitly set.",
      "testable_assertion": "Each Recipient entity exposes a delivery_preferences field; if unset, system defaults are applied."
    },
    {
      "id": "BR-4",
      "rule": "Existing single-recipient shipments must remain valid and fully operational after the model change — no data loss, no behavioral regression.",
      "invariant": true,
      "invariant_justification": "2 million production records depend on the current model. A migration that corrupts or loses recipient data violates data integrity.",
      "testable_assertion": "After migration, every pre-existing shipment has exactly one Recipient with the same name, address, and phone as before, and all existing workflows (tracking, notifications, partner feeds) continue to function identically."
    },
    {
      "id": "BR-5",
      "rule": "Each Recipient on a multi-recipient Shipment must have an independent delivery status.",
      "invariant": true,
      "invariant_justification": "If Recipient A has received their delivery but Recipient B has not, the shipment-level status must reflect the composite state. Collapsing to a single status would misrepresent physical reality.",
      "testable_assertion": "Each Recipient has its own delivery_status field; the Shipment aggregate status is derived from the statuses of all its Recipients."
    },
    {
      "id": "BR-6",
      "rule": "No two Recipients on the same Shipment may have identical addresses.",
      "invariant": false,
      "invariant_justification": "This is a data quality policy, not a physical constraint. A business may choose to allow same-address recipients (e.g., two people at the same office). However, it is a strong default to prevent accidental duplicates.",
      "testable_assertion": "System warns (but does not block) when two Recipients on the same Shipment share an identical normalized address."
    },
    {
      "id": "BR-7",
      "rule": "Partner APIs must continue to receive shipment data in a backward-compatible format until explicitly migrated.",
      "invariant": true,
      "invariant_justification": "Breaking external API contracts disrupts partner operations and may violate contractual SLAs. This is a system boundary integrity constraint.",
      "testable_assertion": "For shipments with one recipient, the partner API payload is byte-identical to the current format. For multi-recipient shipments, the API either sends per-recipient payloads or uses a versioned format agreed upon with each partner."
    }
  ],

  "acceptance_criteria": [
    {
      "id": "AC-1",
      "given": "A new Shipment is being created",
      "when": "The creator specifies multiple Recipients, each with name, address, phone, and delivery preferences",
      "then": "The Shipment is persisted with all Recipients, each individually addressable and each with their own delivery preferences"
    },
    {
      "id": "AC-2",
      "given": "A new Shipment is being created",
      "when": "The creator specifies zero Recipients",
      "then": "The system rejects the creation with a validation error — Shipment requires at least one Recipient"
    },
    {
      "id": "AC-3",
      "given": "An existing single-recipient Shipment created before the model change",
      "when": "The system reads this Shipment after migration",
      "then": "The Shipment has exactly one Recipient with the original name, address, and phone number, and default delivery preferences are applied"
    },
    {
      "id": "AC-4",
      "given": "A multi-recipient Shipment where Recipient A has been delivered and Recipient B has not",
      "when": "A user or system queries the Shipment status",
      "then": "The Shipment shows a composite status (e.g., 'partially delivered'), and each Recipient shows their individual delivery status"
    },
    {
      "id": "AC-5",
      "given": "A multi-recipient Shipment",
      "when": "An external partner API requests this Shipment's data via the current (v1) API",
      "then": "The partner receives a backward-compatible response — either the primary recipient only, or one payload per recipient — without breaking the existing contract"
    },
    {
      "id": "AC-6",
      "given": "A Shipment with multiple Recipients",
      "when": "One Recipient is removed",
      "then": "The removal succeeds only if at least one Recipient remains; otherwise it is rejected (BR-1 enforced)"
    },
    {
      "id": "AC-7",
      "given": "A Shipment with multiple Recipients each having different delivery preferences",
      "when": "The shipment is dispatched for delivery",
      "then": "The routing/fulfillment system generates a delivery plan that respects each Recipient's individual preferences (time windows, signature requirements, etc.)"
    }
  ],

  "edge_cases": [
    {
      "scenario": "A Shipment is created with 50+ Recipients",
      "expected_behavior": "System should enforce a reasonable upper bound on recipients per shipment. The exact limit is a business policy decision, but must exist to prevent abuse and ensure operational feasibility."
    },
    {
      "scenario": "Two Recipients on the same Shipment have conflicting delivery time windows that make a single-route delivery impossible",
      "expected_behavior": "The system should detect this at dispatch time and either split the delivery into multiple routes or surface the conflict to the dispatcher for resolution."
    },
    {
      "scenario": "An existing partner integration sends a shipment update assuming single-recipient format",
      "expected_behavior": "The API accepts the update and applies it to the primary or sole recipient. If the shipment has multiple recipients, the system must not silently overwrite all recipients with the single-recipient payload."
    },
    {
      "scenario": "A recipient is added to a Shipment that is already in-transit",
      "expected_behavior": "Business must define whether mid-transit recipient additions are allowed. If allowed, the routing plan must be recalculated. If not allowed, the addition is rejected with a clear status-based reason."
    },
    {
      "scenario": "Migration of 2 million records — a subset has corrupted or incomplete recipient data",
      "expected_behavior": "Migration must not silently drop records. Rows with invalid data should be flagged for manual review while valid records proceed."
    },
    {
      "scenario": "All Recipients on a multi-recipient Shipment refuse delivery",
      "expected_behavior": "The Shipment moves to a terminal 'all-refused' or 'returned' state, triggering the existing return-to-sender process."
    },
    {
      "scenario": "Notifications (tracking updates, delivery confirmations) for multi-recipient Shipments",
      "expected_behavior": "Each Recipient receives only their own delivery notifications; no Recipient should see another Recipient's contact details or delivery status unless explicitly authorized."
    }
  ],

  "business_impact": {
    "financial": "Enables new revenue streams (e.g., group/split shipments, gift-to-multiple). Migration cost is significant: engineering effort for schema migration of 2M records, partner API versioning, and testing. Risk of revenue loss if partner integrations break during transition.",
    "operational": "Substantial increase in routing complexity — multi-stop deliveries per shipment require updated dispatch logic. Delivery status tracking becomes composite (partially delivered states). Customer support must be retrained on multi-recipient workflows. Migration must be zero-downtime to avoid operational disruption.",
    "user": "Positive for end-users who need multi-recipient delivery. However, UI/UX must handle the added complexity without overwhelming users who still send to one recipient (the 99% case today). Poor handling of the common single-recipient case to accommodate the multi-recipient case would degrade the majority experience.",
    "risk": "HIGH — This touches a core domain aggregate. Risks include: (1) Data migration failure on 2M records, (2) Breaking partner API contracts causing SLA violations, (3) Aggregate boundary confusion if Shipment status derivation from multiple Recipient statuses is not carefully designed, (4) Privacy risk if one Recipient's data leaks to another on the same Shipment.",
    "stakeholders_affected": [
      { "group": "End customers (senders)", "impact": "Gain ability to ship to multiple recipients in one transaction — new capability" },
      { "group": "End customers (recipients)", "impact": "Must receive individualized tracking and notifications; privacy of their data must be protected from co-recipients" },
      { "group": "Courier/delivery drivers", "impact": "Must handle multi-stop routes per shipment; delivery handoff process changes significantly" },
      { "group": "External API partners", "impact": "Must not break on existing single-recipient format; require migration path to multi-recipient format on their own timeline" },
      { "group": "Customer support", "impact": "Must handle new status complexities (partially delivered), recipient-level disputes, and multi-party communication" },
      { "group": "Finance/billing", "impact": "Pricing model must account for multi-recipient shipments — is it one charge or per-recipient? Invoicing and refund logic affected" },
      { "group": "Engineering/platform", "impact": "Schema migration, API versioning, aggregate redesign, event schema changes — high effort across multiple teams" }
    ]
  },

